/* com.matjzing.mapper.FrontVoteMapper.insertFrontVote */
INSERT INTO VOTE (
	  TOPIC_SEQ /**/
	, CANDIDATE_SEQ /**/
	, MEMBER_SEQ /**/
	, COMMENT /**/
	, USE_YN /**/
	, REGISTER_SEQ /**/
	, REGISTER_IP /**/
	, REGISTRATION_DT /**/
	, UPDATER_SEQ /**/
	, UPDATER_IP /**/
	, UPDATE_DT /**/
) VALUES (
	  #{topicSeq}
	, #{candidateSeq}
	, COALESCE(#{memberSeq}, #{registerSeq})
	, #{comment}
	, TRUE
	, #{registerSeq}
	, #{registerIp}
	, NOW(3)
	, #{updaterSeq}
	, #{updaterIp}
	, NOW(3)
)
